async (params, browser) => {
  // Open the tweet
  await browser.open(`${params.tweet_url}`)

  // Wait for page content
  await browser.waitForSelector('[data-testid=\'tweetText\']', 15000)

  // Let page settle
  await browser.wait(1000)

  // Wait for reply box
  await browser.waitForSelector('[data-testid^=\'tweetTextarea\']', 10000)

  // Focus reply box
  await browser.click('[data-testid^=\'tweetTextarea\']')

  // Wait for focus
  await browser.wait(300)

  // Type reply text
  const type_reply = await browser.evaluate(`const txt = params.reply_text; if (txt.length > 280) throw new Error('Reply exceeds 280 characters (' + txt.length + ' chars). Please shorten it.'); const el = document.querySelector('[data-testid^="tweetTextarea"] [contenteditable="true"], [data-testid^="tweetTextarea"][contenteditable="true"], [data-testid^="tweetTextarea"]'); if (!el) throw new Error('Reply textarea not found'); el.focus(); document.execCommand('insertText', false, txt); el.dispatchEvent(new Event('input', {bubbles: true})); return { typed: true, characters: txt.length }`)

  await browser.wait(500)

  // Send reply
  await browser.click('[data-testid=\'tweetButtonInline\'], [data-testid^=\'tweetButton\']')

  // Wait for reply to post
  await browser.wait(2000)

  const result = await browser.evaluate(`return { success: true, message: 'Reply posted successfully' }`)

  return result
}
